 83→/**
 84→ * Manages the directories where the state of Tasks owned by a {@link StreamThread} are
 85→ * stored. Handles creation/locking/unlocking/cleaning of the Task Directories. This class is not
 86→ * thread-safe.
 87→ */
 88→public class StateDirectory implements AutoCloseable {
 89→
 90→    private static final Pattern TASK_DIR_PATH_NAME = Pattern.compile("\\d+_\\d+");
 91→    private static final Pattern NAMED_TOPOLOGY_DIR_PATH_NAME = Pattern.compile("__.+__"); // named topology dirs follow '__Topology-Name__'
 92→    private static final Logger log = LoggerFactory.getLogger(StateDirectory.class);
 93→    static final String LOCK_FILE_NAME = ".lock";
 94→
 95→    /* The process file is used to persist the process id across restarts.
 96→     * For compatibility reasons you should only ever add fields to the json schema
 97→     */
 98→    static final String PROCESS_FILE_NAME = "kafka-streams-process-metadata";
 99→
100→    @JsonIgnoreProperties(ignoreUnknown = true)
101→    static class StateDirectoryProcessFile {
102→        @JsonProperty
103→        private final UUID processId;
104→
105→        // required by jackson -- do not remove, your IDE may be warning that this is unused but it's lying to you
106→        public StateDirectoryProcessFile() {
107→            this.processId = null;
108→        }
109→
110→        StateDirectoryProcessFile(final UUID processId) {
111→            this.processId = processId;
112→        }
113→    }
114→
115→    private final Object taskDirCreationLock = new Object();
116→    private final Time time;
117→    private final String appId;
118→    private final File stateDir;
119→    private final boolean hasPersistentStores;
120→    private final boolean hasNamedTopologies;
121→
122→    private final ConcurrentMap<TaskId, Thread> lockedTasksToOwner = new ConcurrentHashMap<>();
123→
124→    private FileChannel stateDirLockChannel;
125→    private FileLock stateDirLock;
126→
127→    private final StreamsConfig config;
128→    private final Set<TaskId> tasksInLocalState = new ConcurrentSkipListSet<>();
129→    private final Map<TaskId, Long> taskOffsetSums = new ConcurrentHashMap<>();
130→
131→    /**
132→     * Ensures that the state base directory as well as the application's sub-directory are created.
133→     *
134→     * @param config              streams application configuration to read the root state directory path
135→     * @param time                system timer used to execute periodic cleanup procedure
136→     * @param hasPersistentStores only when the application's topology does have stores persisted on local file
137→     *                            system, we would go ahead and auto-create the corresponding application / task / store
138→     *                            directories whenever necessary; otherwise no directories would be created.
139→     * @param hasNamedTopologies  whether this application is composed of independent named topologies
140→     *
141→     * @throws ProcessorStateException if the base state directory or application state directory does not exist
142→     *                                 and could not be created when hasPersistentStores is enabled.
143→     */
144→    public StateDirectory(final StreamsConfig config, final Time time, final boolean hasPersistentStores, final boolean hasNamedTopologies) {
145→        this.time = time;
146→        this.hasPersistentStores = hasPersistentStores;
147→        this.hasNamedTopologies = hasNamedTopologies;
148→        this.appId = config.getString(StreamsConfig.APPLICATION_ID_CONFIG);
149→        this.config = config;
150→        final String stateDirName = config.getString(StreamsConfig.STATE_DIR_CONFIG);
151→        final File baseDir = new File(stateDirName);
152→        stateDir = new File(baseDir, appId);
153→
154→        if (this.hasPersistentStores) {
155→            if (!baseDir.exists() && !baseDir.mkdirs()) {
156→                throw new ProcessorStateException(
157→                    String.format("base state directory [%s] doesn't exist and couldn't be created", stateDirName));
158→            }
159→            if (!stateDir.exists() && !stateDir.mkdir()) {
160→                throw new ProcessorStateException(
161→                    String.format("state directory [%s] doesn't exist and couldn't be created", stateDir.getPath()));
162→            } else if (stateDir.exists() && !stateDir.isDirectory()) {
163→                throw new ProcessorStateException(
164→                    String.format("state directory [%s] can't be created as there is an existing file with the same name", stateDir.getPath()));
165→            }
166→
167→            if (stateDirName.startsWith(System.getProperty("java.io.tmpdir"))) {
168→                log.warn("Using an OS temp directory in the state.dir property can cause failures with writing" +
169→                    " the checkpoint file due to the fact that this directory can be cleared by the OS." +
170→                    " Resolved state.dir: [" + stateDirName + "]");
171→
172→            }
173→            // change the dir permission to "rwxr-x---" to avoid world readable
174→            configurePermissions(baseDir);
175→            configurePermissions(stateDir);
176→        }
177→    }
178→
179→    private void configurePermissions(final File file) {
180→        final Path path = file.toPath();
181→        if (path.getFileSystem().supportedFileAttributeViews().contains("posix")) {
182→            final Set<PosixFilePermission> perms = EnumSet.of(
183→                    PosixFilePermission.OWNER_READ,
184→                    PosixFilePermission.OWNER_WRITE,
185→                    PosixFilePermission.OWNER_EXECUTE,
186→                    PosixFilePermission.GROUP_READ,
187→                    PosixFilePermission.GROUP_EXECUTE
188→            );
189→            if (config.getBoolean(StreamsConfig.ALLOW_OS_GROUP_WRITE_ACCESS_CONFIG)) {
190→                perms.add(PosixFilePermission.GROUP_WRITE);
191→            }
192→            try {
193→                Files.setPosixFilePermissions(path, perms);
194→            } catch (final IOException e) {
195→                log.error("Error changing permissions for the directory {} ", path, e);
196→            }
197→        } else {
198→            boolean set = file.setReadable(true, true);
199→            set &= file.setWritable(true, true);
200→            set &= file.setExecutable(true, true);
201→            if (!set) {
202→                log.error("Failed to change permissions for the directory {}", file);
203→            }
204→        }
205→    }
206→
207→    /**
208→     * @return true if the state directory was successfully locked
209→     */
210→    private boolean lockStateDirectory() {
211→        final File lockFile = new File(stateDir, LOCK_FILE_NAME);
212→        try {
213→            stateDirLockChannel = FileChannel.open(lockFile.toPath(), StandardOpenOption.CREATE, StandardOpenOption.WRITE);
214→            stateDirLock = tryLock(stateDirLockChannel);
215→        } catch (final IOException e) {
216→            log.error("Unable to lock the state directory due to unexpected exception", e);
217→            throw new ProcessorStateException(String.format("Failed to lock the state directory [%s] during startup",
218→                stateDir.getAbsolutePath()), e);
219→        }
220→        return stateDirLock != null;
221→    }
222→
223→    /**
224→     * @throws LockException If another process already locks any of StateDirectory
225→     * @throws ProcessorStateException if any of task directory does not exist and could not be created
226→    */
227→    public void initializeStartupStores(final TopologyMetadata topologyMetadata,
228→                                        final LogContext logContext,
229→                                        final StreamsMetricsImpl metricsImpl) {
230→        final List<TaskDirectory> nonEmptyTaskDirectories = listNonEmptyTaskDirectories();
231→        if (hasPersistentStores && !nonEmptyTaskDirectories.isEmpty()) {
232→            final boolean eosEnabled = StreamsConfigUtils.eosEnabled(config);
233→
234→            // Initialize thread-specific resources needed to open stores in the state directory
235→            final String threadLogPrefix = String.format("[%s]", Thread.currentThread().getName());
236→            final ThreadCache dummyCache = new ThreadCache(new LogContext(threadLogPrefix), 0L, metricsImpl);
237→
238→            // discover all non-empty task directories in StateDirectory
239→            for (final TaskDirectory taskDirectory : nonEmptyTaskDirectories) {
240→                final String dirName = taskDirectory.file().getName();
241→                final TaskId task = parseTaskDirectoryName(dirName, taskDirectory.namedTopology());
242→                final ProcessorTopology subTopology = topologyMetadata.buildSubtopology(task);
243→
244→                // we still check if the task's sub-topology is stateful, even though we know its directory contains state,
245→                // because it's possible that the topology has changed since that data was written, and is now stateless
246→                // this therefore prevents us from creating unnecessary stores just because of some left-over state
247→                if (subTopology.hasStateWithChangelogs()) {
248→                    final Set<TopicPartition> inputPartitions = topologyMetadata.nodeToSourceTopics(task).values().stream()
249→                            .flatMap(Collection::stream)
250→                            .map(t -> new TopicPartition(t, task.partition()))
251→                            .collect(Collectors.toSet());
252→                    // Open a temporary state manager that will open the stores inside the subtopology
253→                    final ProcessorStateManager temporaryStateManager = ProcessorStateManager.createStartupTaskStateManager(
254→                        task,
255→                        eosEnabled,
256→                        logContext,
257→                        this,
258→                        subTopology.storeToChangelogTopic(),
259→                        inputPartitions
260→                    );
261→
262→                    final StartupContext initContext = new StartupContext(task, config, temporaryStateManager, metricsImpl, dummyCache);
263→                    try {
264→                        // We only handle TaskCorruptedException at this point. Any other exception is considered fatal.
265→                        StateManagerUtil.registerStateStores(log, threadLogPrefix, subTopology, temporaryStateManager, this, initContext);
266→                        temporaryStateManager.checkpoint();
267→                    } catch (final TaskCorruptedException tce) {
268→                        // At this point, we only log a warning and continue with the startup store initialization.
269→                        // The task-corrupted exception will be handled in the first Task assignment phase.
270→                        log.warn("Failed to register startup state stores for task {}: {}", task, tce.getMessage());
271→                    } finally {
272→                        // Make sure the state manager writes the local checkpoint file before closing the stores
273→                        // This will be replaced in the future when removing the checkpoint file dependency.
274→                        temporaryStateManager.close();
275→                    }
276→                    tasksInLocalState.add(task);
277→                }
278→            }
279→        }
280→    }
281→
282→    public boolean hasStartupTasks() {
283→        return !tasksInLocalState.isEmpty();
284→    }
285→
286→    public synchronized boolean removeStartupState(final TaskId taskId) {
287→        final boolean removed = tasksInLocalState.remove(taskId);
288→        if (removed) {
289→            lockedTasksToOwner.put(taskId, Thread.currentThread());
290→        }
291→        return removed;
292→    }
293→
294→
295→    private void unlockStartupStores() {
296→        for (final TaskId task : tasksInLocalState) {
297→            unlock(task);
298→        }
299→    }
300→
301→    public Map<TaskId, Long> taskOffsetSums(final Set<TaskId> tasks) {
302→        return taskOffsetSums.entrySet().stream()
303→                .filter(e -> tasks.contains(e.getKey()))
304→                .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
305→    }
306→
307→    public void updateTaskOffsets(final TaskId taskId, final Map<TopicPartition, Long> changelogOffsets) {
308→        if (!changelogOffsets.isEmpty()) {
309→            taskOffsetSums.put(taskId, sumOfChangelogOffsets(taskId, changelogOffsets));
310→        }
311→    }
312→
313→    public void removeTaskOffsets(final TaskId taskId) {
314→        taskOffsetSums.remove(taskId);
315→    }
316→
317→    private long sumOfChangelogOffsets(final TaskId taskId, final Map<TopicPartition, Long> changelogOffsets) {
318→        long offsetSum = 0L;
319→        for (final Map.Entry<TopicPartition, Long> changelogEntry : changelogOffsets.entrySet()) {
320→            final long offset = changelogEntry.getValue();
321→
322→            if (offset != OffsetCheckpoint.OFFSET_UNKNOWN) {
323→                if (offset < 0) {
324→                    throw new StreamsException(
325→                            new IllegalStateException("Expected not to get a sentinel offset, but got: " + changelogEntry),
326→                            taskId);
327→                }
328→                offsetSum += offset;
329→                if (offsetSum < 0) {
330→                    log.warn("Sum of changelog offsets for task {} overflowed, pinning to Long.MAX_VALUE", taskId);
331→                    return Long.MAX_VALUE;
332→                }
333→            }
334→        }
335→
336→        return offsetSum;
337→    }
338→
339→    public UUID initializeProcessId() {
340→        if (!hasPersistentStores) {
341→            final UUID processId = UUID.randomUUID();
342→            log.info("Created new process id: {}", processId);
343→            return processId;
344→        }
345→
346→        if (!lockStateDirectory()) {
347→            log.error("Unable to obtain lock as state directory is already locked by another process");
348→            throw new StreamsException(String.format("Unable to initialize state, this can happen if multiple instances of " +
349→                                           "Kafka Streams are running in the same state directory " +
350→                                           "(current state directory is [%s]", stateDir.getAbsolutePath()));
351→        }
352→
353→        final File processFile = new File(stateDir, PROCESS_FILE_NAME);
354→        final ObjectMapper mapper = new ObjectMapper();
355→
356→        try {
357→            if (processFile.exists()) {
358→                try {
359→                    final StateDirectoryProcessFile processFileData = mapper.readValue(processFile, StateDirectoryProcessFile.class);
360→                    log.info("Reading UUID from process file: {}", processFileData.processId);
361→                    if (processFileData.processId != null) {
362→                        return processFileData.processId;
363→                    }
364→                } catch (final Exception e) {
365→                    log.warn("Failed to read json process file", e);
366→                }
367→            }
368→
369→            final StateDirectoryProcessFile processFileData = new StateDirectoryProcessFile(UUID.randomUUID());
370→            log.info("No process id found on disk, got fresh process id {}", processFileData.processId);
371→
372→            mapper.writeValue(processFile, processFileData);
373→            return processFileData.processId;
374→        } catch (final IOException e) {
375→            log.error("Unable to read/write process file due to unexpected exception", e);
376→            throw new ProcessorStateException(e);
377→        }
378→    }
379→
380→    /**
381→     * Get or create the directory for the provided {@link TaskId}.
382→     * @return directory for the {@link TaskId}
383→     * @throws ProcessorStateException if the task directory does not exist and could not be created
384→     */
385→    public File getOrCreateDirectoryForTask(final TaskId taskId) {
386→        final File taskParentDir = getTaskDirectoryParentName(taskId);
387→        final File taskDir = new File(taskParentDir, StateManagerUtil.toTaskDirString(taskId));
388→        if (hasPersistentStores) {
389→            if (!taskDir.exists()) {
390→                synchronized (taskDirCreationLock) {
391→                    // to avoid a race condition, we need to check again if the directory does not exist:
392→                    // otherwise, two threads might pass the outer `if` (and enter the `then` block),
393→                    // one blocks on `synchronized` while the other creates the directory,
394→                    // and the blocking one fails when trying to create it after it's unblocked
395→                    if (!taskParentDir.exists() && !taskParentDir.mkdir()) {
396→                        throw new ProcessorStateException(
397→                            String.format("Parent [%s] of task directory [%s] doesn't exist and couldn't be created",
398→                                taskParentDir.getPath(), taskDir.getPath()));
399→                    }
400→                    if (!taskDir.exists() && !taskDir.mkdir()) {
401→                        throw new ProcessorStateException(
402→                            String.format("task directory [%s] doesn't exist and couldn't be created", taskDir.getPath()));
403→                    }
404→                }
405→            } else if (!taskDir.isDirectory()) {
406→                throw new ProcessorStateException(
407→                    String.format("state directory [%s] can't be created as there is an existing file with the same name", taskDir.getPath()));
408→            }
409→        }
410→        return taskDir;
411→    }
412→
413→    private File getTaskDirectoryParentName(final TaskId taskId) {
414→        final String namedTopology = taskId.topologyName();
415→        if (namedTopology != null) {
416→            if (!hasNamedTopologies) {
417→                throw new IllegalStateException("Tried to lookup taskId with named topology, but StateDirectory thinks hasNamedTopologies = false");
418→            }
419→            return new File(stateDir, getNamedTopologyDirName(namedTopology));
420→        } else {
421→            return stateDir;
422→        }
423→    }
424→
425→    private String getNamedTopologyDirName(final String topologyName) {
426→        return "__" + topologyName + "__";
427→    }
428→
429→    /**
430→     * @return The File handle for the checkpoint in the given task's directory
431→     */
432→    File checkpointFileFor(final TaskId taskId) {
433→        return new File(getOrCreateDirectoryForTask(taskId), StateManagerUtil.CHECKPOINT_FILE_NAME);
434→    }
435→
436→    /**
437→     * Decide if the directory of the task is empty or not
438→     */
439→    boolean directoryForTaskIsEmpty(final TaskId taskId) {
440→        final File taskDir = getOrCreateDirectoryForTask(taskId);
441→
442→        return taskDirIsEmpty(taskDir);
443→    }
444→
445→    private boolean taskDirIsEmpty(final File taskDir) {
446→        final File[] storeDirs = taskDir.listFiles(pathname ->
447→                !pathname.getName().equals(CHECKPOINT_FILE_NAME));
448→
449→        boolean taskDirEmpty = true;
450→
451→        // if the task is stateless, storeDirs would be null
452→        if (storeDirs != null && storeDirs.length > 0) {
453→            for (final File file : storeDirs) {
454→                // We removed the task directory locking but some upgrading applications may still have old lock files on disk,
455→                // we just lazily delete those in this method since it's the only thing that would be affected by these
456→                if (file.getName().endsWith(LOCK_FILE_NAME)) {
457→                    if (!file.delete()) {
458→                        // If we hit an error deleting this just ignore it and move on, we'll retry again at some point
459→                        log.warn("Error encountered deleting lock file in {}", taskDir);
460→                    }
461→                } else {
462→                    // If it's not a lock file then the directory is not empty,
463→                    // but finish up the loop in case there's a lock file left to delete
464→                    log.trace("TaskDir {} was not empty, found {}", taskDir, file);
465→                    taskDirEmpty = false;
466→                }
467→            }
468→        }
469→        return taskDirEmpty;
470→    }
471→
472→    /**
473→     * Get or create the directory for the global stores.
474→     * @return directory for the global stores
475→     * @throws ProcessorStateException if the global store directory does not exists and could not be created
476→     */
477→    File globalStateDir() {
478→        final File dir = new File(stateDir, "global");
479→        if (hasPersistentStores) {
480→            if (!dir.exists() && !dir.mkdir()) {
481→                throw new ProcessorStateException(
482→                    String.format("global state directory [%s] doesn't exist and couldn't be created", dir.getPath()));
483→            } else if (dir.exists() && !dir.isDirectory()) {
484→                throw new ProcessorStateException(
485→                    String.format("global state directory [%s] can't be created as there is an existing file with the same name", dir.getPath()));
486→            }
487→        }
488→        return dir;
489→    }
490→
491→    private String logPrefix() {
492→        return String.format("stream-thread [%s]", Thread.currentThread().getName());
493→    }
494→
495→    /**
496→     * Get the lock for the {@link TaskId}s directory if it is available
497→     * @param taskId task id
498→     * @return true if successful
499→     */
500→    synchronized boolean lock(final TaskId taskId) {
501→        if (!hasPersistentStores) {
502→            return true;
503→        }
504→
505→        final Thread lockOwner = lockedTasksToOwner.get(taskId);
506→        if (lockOwner != null) {
507→            if (lockOwner.equals(Thread.currentThread())) {
508→                log.trace("{} Found cached state dir lock for task {}", logPrefix(), taskId);
509→                // we already own the lock
510→                return true;
511→            } else {
512→                // another thread owns the lock
513→                return false;
514→            }
515→        } else if (!stateDir.exists()) {
516→            log.error("Tried to lock task directory for {} but the state directory does not exist", taskId);
517→            throw new IllegalStateException("The state directory has been deleted");
518→        } else {
519→            lockedTasksToOwner.put(taskId, Thread.currentThread());
520→            return true;
521→        }
522→    }
523→
524→    /**
525→     * Unlock the state directory for the given {@link TaskId}.
526→     */
527→    synchronized void unlock(final TaskId taskId) {
528→        final Thread lockOwner = lockedTasksToOwner.get(taskId);
529→        if (lockOwner != null && lockOwner.equals(Thread.currentThread())) {
530→            lockedTasksToOwner.remove(taskId);
531→            log.debug("{} Released state dir lock for task {}", logPrefix(), taskId);
532→        }
533→    }
534→
535→    /**
536→     * Expose for tests.
537→     */
538→    Thread lockOwner(final TaskId taskId) {
539→        return lockedTasksToOwner.get(taskId);
540→    }
