602→    /**
603→     * Remove the directories for any {@link TaskId}s that are no-longer
604→     * owned by this {@link StreamThread} and aren't locked by either
605→     * another process or another {@link StreamThread}
606→     * @param cleanupDelayMs only remove directories if they haven't been modified for at least
607→     *                       this amount of time (milliseconds)
608→     */
609→    public synchronized void cleanRemovedTasks(final long cleanupDelayMs) {
610→        try {
611→            cleanRemovedTasksCalledByCleanerThread(cleanupDelayMs);
612→        } catch (final Exception cannotHappen) {
613→            throw new IllegalStateException("Should have swallowed exception.", cannotHappen);
614→        }
615→    }
616→
617→    private void cleanRemovedTasksCalledByCleanerThread(final long cleanupDelayMs) {
618→        for (final TaskDirectory taskDir : listAllTaskDirectories()) {
619→            final String dirName = taskDir.file().getName();
620→            final TaskId id = parseTaskDirectoryName(dirName, taskDir.namedTopology());
621→            if (!lockedTasksToOwner.containsKey(id)) {
622→                try {
623→                    if (lock(id)) {
624→                        final long now = time.milliseconds();
625→                        final long lastModifiedMs = taskDir.file().lastModified();
626→                        if (now - cleanupDelayMs > lastModifiedMs) {
627→                            removeTaskOffsets(id);
628→                            log.info("{} Deleting obsolete state directory {} for task {} as {}ms has elapsed (cleanup delay is {}ms).",
629→                                logPrefix(), dirName, id, now - lastModifiedMs, cleanupDelayMs);
630→                            removeStartupState(id);
631→                            Utils.delete(taskDir.file());
632→                        }
633→                    }
634→                } catch (final IOException exception) {
635→                    log.warn(
636→                        String.format("%s Swallowed the following exception during deletion of obsolete state directory %s for task %s:",
637→                            logPrefix(), dirName, id),
638→                        exception
639→                    );
640→                } finally {
641→                    unlock(id);
642→                }
643→            }
644→        }
645→        // Ok to ignore returned exception as it should be swallowed
646→        maybeCleanEmptyNamedTopologyDirs(true);
647→    }
648→
649→    /**
650→     * Cleans up any leftover named topology directories that are empty, if any exist
651→     * @param logExceptionAsWarn if true, an exception will be logged as a warning
652→     *                       if false, an exception will be logged as error
653→     * @return the first IOException to be encountered
654→     */
655→    private IOException maybeCleanEmptyNamedTopologyDirs(final boolean logExceptionAsWarn) {
656→        if (!hasNamedTopologies) {
657→            return null;
658→        }
659→
660→        final AtomicReference<IOException> firstException = new AtomicReference<>(null);
661→        final File[] namedTopologyDirs = stateDir.listFiles(pathname ->
662→                pathname.isDirectory() && NAMED_TOPOLOGY_DIR_PATH_NAME.matcher(pathname.getName()).matches()
663→        );
664→        if (namedTopologyDirs != null) {
665→            for (final File namedTopologyDir : namedTopologyDirs) {
666→                final String topologyName = parseNamedTopologyFromDirectory(namedTopologyDir.getName());
667→                final Set<TaskId> taskKeys = taskOffsetSums.keySet();
668→                taskKeys.removeIf(taskId -> taskId.topologyName().equals(topologyName));
669→                final File[] contents = namedTopologyDir.listFiles();
670→                if (contents != null && contents.length == 0) {
671→                    try {
672→                        Utils.delete(namedTopologyDir);
673→                    } catch (final IOException exception) {
674→                        if (logExceptionAsWarn) {
675→                            log.warn(
676→                                String.format("%sSwallowed the following exception during deletion of named topology directory %s",
677→                                    logPrefix(), namedTopologyDir.getName()),
678→                                exception
679→                            );
680→                        } else {
681→                            log.error(
682→                                String.format("%s Failed to delete named topology directory %s with exception:",
683→                                    logPrefix(), namedTopologyDir.getName()),
684→                                exception
685→                            );
686→                        }
687→                        firstException.compareAndSet(null, exception);
688→                    }
689→                }
690→            }
691→        }
692→        return firstException.get();
693→    }
