695→    /**
696→     * Clears out any local state found for the given NamedTopology after it was removed
697→     *
698→     * @throws StreamsException if cleanup failed
699→     */
700→    public void clearLocalStateForNamedTopology(final String topologyName) {
701→        final File namedTopologyDir = new File(stateDir, getNamedTopologyDirName(topologyName));
702→        if (!namedTopologyDir.exists() || !namedTopologyDir.isDirectory()) {
703→            log.debug("Tried to clear out the local state for NamedTopology {} but none was found", topologyName);
704→        }
705→        try {
706→            final Set<TaskId> taskKeys = taskOffsetSums.keySet();
707→            taskKeys.removeIf(taskId -> taskId.topologyName().equals(topologyName));
708→            Utils.delete(namedTopologyDir);
709→        } catch (final IOException e) {
710→            log.error("Hit an unexpected error while clearing local state for topology " + topologyName, e);
711→            throw new StreamsException("Unable to delete state for the named topology " + topologyName,
712→                                       e, new TaskId(-1, -1, topologyName)); // use dummy taskid to report source topology for this error
713→        }
714→    }
