195→    /**
196→     * Kafka Streams states are the possible state that a Kafka Streams instance can be in.
197→     * An instance must only be in one state at a time.
198→     * The expected state transition with the following defined states is:
199→     *
200→     * <pre>
201→     *                 +--------------+
202→     *         +&lt;----- | Created (0)  |
203→     *         |       +-----+--------+
204→     *         |             |
205→     *         |             v
206→     *         |       +----+--+------+
207→     *         |       | Re-          |
208→     *         +&lt;----- | Balancing (1)| --------&gt;+
209→     *         |       +-----+-+------+          |
210→     *         |             | ^                 |
211→     *         |             v |                 |
212→     *         |       +--------------+          v
213→     *         |       | Running (2)  | --------&gt;+
214→     *         |       +------+-------+          |
215→     *         |              |                  |
216→     *         |              v                  |
217→     *         |       +------+-------+     +----+-------+
218→     *         +-----&gt; | Pending      |     | Pending    |
219→     *                 | Shutdown (3) |     | Error (5)  |
220→     *                 +------+-------+     +-----+------+
221→     *                        |                   |
222→     *                        v                   v
223→     *                 +------+-------+     +-----+--------+
224→     *                 | Not          |     | Error (6)    |
225→     *                 | Running (4)  |     +--------------+
226→     *                 +--------------+
227→     *
228→     *
229→     * </pre>
230→     * Note the following:
231→     * <ul>
232→     *   <li>
233→     *     RUNNING state will transit to REBALANCING if any of its threads is in PARTITION_REVOKED or PARTITIONS_ASSIGNED state
234→     *   </li>
235→     *   <li>
236→     *     REBALANCING state will transit to RUNNING if all of its threads are in RUNNING state
237→     *     (Note: a thread transits to RUNNING state, if all active tasks got restored are ready for processing.
238→     *     Standby tasks are not considered.)
239→     *   </li>
240→     *   <li>
241→     *     Any state except NOT_RUNNING, PENDING_ERROR or ERROR can go to PENDING_SHUTDOWN (whenever close is called)
242→     *   </li>
243→     *   <li>
244→     *     PENDING_SHUTDOWN and PENDING_ERROR are transitory states where the Streams application gracefully closes
245→     *     its existing resources before transitioning into their corresponding terminal states. These states are
246→     *     not recoverable, and only a restart would get an application back to the RUNNING state.
247→     *   </li>
248→     *   <li>
249→     *     Of special importance: If the global stream thread dies, or all stream threads die (or both) then
250→     *     the instance will be in the ERROR state. The user will not need to close it.
251→     *   </li>
252→     * </ul>
253→     */
254→    public enum State {
255→        // Note: if you add a new state, check the below methods and how they are used within Streams to see if
256→        // any of them should be updated to include the new state. For example a new shutdown path or terminal
257→        // state would likely need to be included in methods like isShuttingDown(), hasCompletedShutdown(), etc.
258→        CREATED(1, 3),          // 0
259→        REBALANCING(2, 3, 5),   // 1
260→        RUNNING(1, 2, 3, 5),    // 2
261→        PENDING_SHUTDOWN(4),    // 3
262→        NOT_RUNNING,            // 4
263→        PENDING_ERROR(6),       // 5
264→        ERROR;                  // 6
265→
266→        private final Set<Integer> validTransitions = new HashSet<>();
267→
268→        State(final Integer... validTransitions) {
269→            this.validTransitions.addAll(Arrays.asList(validTransitions));
270→        }
271→
272→        public boolean hasNotStarted() {
273→            return equals(CREATED);
274→        }
275→
276→        public boolean isRunningOrRebalancing() {
277→            return equals(RUNNING) || equals(REBALANCING);
278→        }
279→
280→        public boolean isShuttingDown() {
281→            return equals(PENDING_SHUTDOWN) || equals(PENDING_ERROR);
282→        }
283→
284→        public boolean hasCompletedShutdown() {
285→            return equals(NOT_RUNNING) || equals(ERROR);
286→        }
287→
288→        public boolean hasStartedOrFinishedShuttingDown() {
289→            return isShuttingDown() || hasCompletedShutdown();
290→        }
291→
292→        public boolean isValidTransition(final State newState) {
293→            return validTransitions.contains(newState.ordinal());
294→        }
295→    }
