484→    private void replaceStreamThread(final Throwable throwable) {
485→        if (globalStreamThread != null && Thread.currentThread().getName().equals(globalStreamThread.getName())) {
486→            log.warn("The global thread cannot be replaced. Reverting to shutting down the client.");
487→            log.error("Encountered the following exception during processing " +
488→                    " The streams client is going to shut down now. ", throwable);
489→            closeToError();
