1102→    /**
1103→     * Adds and starts a stream thread in addition to the stream threads that are already running in this
1104→     * Kafka Streams client.
1105→     * <p>
1106→     * Since the number of stream threads increases, the sizes of the caches in the new stream thread
1107→     * and the existing stream threads are adapted so that the sum of the cache sizes over all stream
1108→     * threads does not exceed the total cache size specified in configuration
1109→     * {@link StreamsConfig#STATESTORE_CACHE_MAX_BYTES_CONFIG}.
1110→     * <p>
1111→     * Stream threads can only be added if this Kafka Streams client is in state RUNNING or REBALANCING.
1112→     *
1113→     * @return name of the added stream thread or empty if a new stream thread could not be added
1114→     */
1115→    public Optional<String> addStreamThread() {
1116→        if (isRunningOrRebalancing()) {
1117→            final StreamThread streamThread;
1118→            synchronized (changeThreadCount) {
1119→                final int threadIdx = nextThreadIndex();
1120→                final int numLiveThreads = numLiveStreamThreads();
1121→                final long cacheSizePerThread = cacheSizePerThread(numLiveThreads + 1);
1122→                log.info("Adding StreamThread-{}, there will now be {} live threads and the new cache size per thread is {}",
1123→                         threadIdx, numLiveThreads + 1, cacheSizePerThread);
1124→                resizeThreadCache(cacheSizePerThread);
1125→                // Creating thread should hold the lock in order to avoid duplicate thread index.
1126→                // If the duplicate index happen, the metadata of thread may be duplicate too.
1127→                streamThread = createAndAddStreamThread(cacheSizePerThread, threadIdx);
1128→            }
1129→
1130→            synchronized (stateLock) {
1131→                if (isRunningOrRebalancing()) {
1132→                    streamThread.start();
1133→                    return Optional.of(streamThread.getName());
1134→                } else {
1135→                    log.warn("Terminating the new thread because the Kafka Streams client is in state {}", state);
1136→                    streamThread.shutdown(org.apache.kafka.streams.CloseOptions.GroupMembershipOperation.LEAVE_GROUP);
1137→                    threads.remove(streamThread);
1138→                    final long cacheSizePerThread = cacheSizePerThread(numLiveStreamThreads());
1139→                    log.info("Resizing thread cache due to terminating added thread, new cache size per thread is {}", cacheSizePerThread);
1140→                    resizeThreadCache(cacheSizePerThread);
1141→                    return Optional.empty();
1142→                }
1143→            }
1144→        } else {
1145→            log.warn("Cannot add a stream thread when Kafka Streams client is in state {}", state);
1146→            return Optional.empty();
1147→        }
1148→    }
