1255→    /*
1256→     * Takes a snapshot and counts the number of stream threads which are not in PENDING_SHUTDOWN or DEAD
1257→     *
1258→     * Note: iteration over SynchronizedList is not thread safe, so it must be manually synchronized. However, we may
1259→     * require other locks when looping threads, and it could cause deadlock. Hence, we create a copy to avoid holding
1260→     * threads lock when looping threads.
1261→     *
1262→     * @return number of alive stream threads
1263→     */
1264→    private int numLiveStreamThreads() {
1265→        final AtomicInteger numLiveThreads = new AtomicInteger(0);
1266→
1267→        synchronized (threads) {
1268→            processStreamThread(thread -> {
1269→                if (thread.state() == StreamThread.State.DEAD) {
1270→                    log.debug("Trimming thread {} from the threads list since it's state is {}", thread.getName(), StreamThread.State.DEAD);
1271→                    threads.remove(thread);
1272→                } else if (thread.state() == StreamThread.State.PENDING_SHUTDOWN) {
1273→                    log.debug("Skipping thread {} from num live threads computation since it's state is {}",
1274→                              thread.getName(), StreamThread.State.PENDING_SHUTDOWN);
1275→                } else {
1276→                    numLiveThreads.incrementAndGet();
1277→                }
1278→            });
1279→            return numLiveThreads.get();
1280→        }
1281→    }
1282→
1283→    private int nextThreadIndex() {
1284→        final HashSet<String> allLiveThreadNames = new HashSet<>();
1285→        final AtomicInteger maxThreadId = new AtomicInteger(1);
1286→        synchronized (threads) {
1287→            processStreamThread(thread -> {
1288→                // trim any DEAD threads from the list, so we can reuse the thread.id
1289→                // this is only safe to do once the thread has fully completed shutdown
1290→                if (thread.state() == StreamThread.State.DEAD) {
1291→                    threads.remove(thread);
1292→                } else {
1293→                    allLiveThreadNames.add(thread.getName());
1294→                    // Assume threads are always named with the "-StreamThread-<threadId>" suffix
1295→                    final int threadId = Integer.parseInt(thread.getName().substring(thread.getName().lastIndexOf("-") + 1));
1296→                    if (threadId > maxThreadId.get()) {
1297→                        maxThreadId.set(threadId);
1298→                    }
1299→                }
1300→            });
1301→
1302→            final String baseName = clientId + "-StreamThread-";
1303→            for (int i = 1; i <= maxThreadId.get(); i++) {
1304→                final String name = baseName + i;
1305→                if (!allLiveThreadNames.contains(name)) {
1306→                    return i;
1307→                }
1308→            }
1309→            // It's safe to use threads.size() rather than getNumLiveStreamThreads() to infer the number of threads
1310→            // here since we trimmed any DEAD threads earlier in this method while holding the lock
1311→            return threads.size() + 1;
1312→        }
1313→    }
