 46→class Tasks implements TasksRegistry {
 47→    private final Logger log;
 48→
 49→    // note that these two maps may be accessed by concurrent threads and hence
 50→    // should be synchronized when accessed
 51→    private final Map<TaskId, StreamTask> activeTasksPerId = new TreeMap<>();
 52→    private final Map<TaskId, StandbyTask> standbyTasksPerId = new TreeMap<>();
 53→
 54→    // Tasks may have been assigned for a NamedTopology that is not yet known by this host. When that occurs we stash
 55→    // these unknown tasks until either the corresponding NamedTopology is added and we can create them at last, or
 56→    // we receive a new assignment and they are revoked from the thread.
 57→    private final Map<TaskId, Set<TopicPartition>> pendingActiveTasksToCreate = new HashMap<>();
 58→    private final Map<TaskId, Set<TopicPartition>> pendingStandbyTasksToCreate = new HashMap<>();
 59→    private final Set<Task> pendingTasksToInit = new HashSet<>();
 60→    private final Set<Task> pendingTasksToClose = new HashSet<>();
 61→    private final Set<TaskId> failedTaskIds = new HashSet<>();
 62→
 63→    private final Map<TopicPartition, StreamTask> activeTasksPerPartition = new HashMap<>();
 64→
 65→    Tasks(final LogContext logContext) {
 66→        this.log = logContext.logger(getClass());
 67→    }
