 75→    @Override
 76→    public Map<TaskId, Set<TopicPartition>> drainPendingActiveTasksForTopologies(final Set<String> currentTopologies) {
 77→        final Map<TaskId, Set<TopicPartition>> pendingActiveTasksForTopologies =
 78→            filterMap(pendingActiveTasksToCreate, t -> currentTopologies.contains(t.getKey().topologyName()));
 79→
 80→        pendingActiveTasksToCreate.keySet().removeAll(pendingActiveTasksForTopologies.keySet());
 81→
 82→        return pendingActiveTasksForTopologies;
