216→    @Override
217→    public synchronized void addStandbyTask(final StandbyTask task) {
218→        final TaskId taskId = task.id();
219→
220→        if (standbyTasksPerId.containsKey(taskId)) {
221→            throw new IllegalStateException("Attempted to create an standby task that we already own: " + taskId);
222→        }
223→
224→        if (activeTasksPerId.containsKey(taskId)) {
225→            throw new IllegalStateException("Attempted to create an standby task while we already own its active: " + taskId);
226→        }
227→
228→        standbyTasksPerId.put(taskId, task);
229→    }
