260→    @Override
261→    public synchronized void replaceStandbyWithActive(final StreamTask activeTask) {
262→        final TaskId taskId = activeTask.id();
263→        if (standbyTasksPerId.remove(taskId) == null) {
264→            throw new IllegalStateException("Attempted to convert unknown standby task to stream task: " + taskId);
265→        }
266→
267→        activeTasksPerId.put(activeTask.id(), activeTask);
268→        for (final TopicPartition topicPartition : activeTask.inputPartitions()) {
269→            activeTasksPerPartition.put(topicPartition, activeTask);
270→        }
271→    }
