289→    private void removePartitionsForActiveTask(final TaskId taskId) {
290→        final Set<TopicPartition> toBeRemoved = activeTasksPerPartition.entrySet().stream()
291→            .filter(e -> e.getValue().id().equals(taskId))
292→            .map(Map.Entry::getKey)
293→            .collect(Collectors.toSet());
294→        toBeRemoved.forEach(activeTasksPerPartition::remove);
295→    }
