17→package org.apache.kafka.streams.processor.internals;
18→
19→import org.apache.kafka.streams.errors.TaskMigratedException;
20→import org.apache.kafka.streams.processor.Cancellable;
21→import org.apache.kafka.streams.processor.PunctuationType;
22→
23→import java.util.PriorityQueue;
24→
25→public class PunctuationQueue {
26→
27→    private final PriorityQueue<PunctuationSchedule> pq = new PriorityQueue<>();
28→
29→    public Cancellable schedule(final PunctuationSchedule sched) {
30→        synchronized (pq) {
31→            pq.add(sched);
32→        }
33→        return sched.cancellable();
34→    }
35→
36→    public void close() {
37→        synchronized (pq) {
38→            pq.clear();
39→        }
40→    }
41→
42→    /**
43→     * @throws TaskMigratedException if the task producer got fenced (EOS only)
44→     */
45→    boolean maybePunctuate(final long timestamp, final PunctuationType type, final ProcessorNodePunctuator processorNodePunctuator) {
46→        synchronized (pq) {
47→            boolean punctuated = false;
48→            PunctuationSchedule top = pq.peek();
49→            while (top != null && top.timestamp <= timestamp) {
50→                final PunctuationSchedule sched = top;
51→                pq.poll();
52→
53→                if (!sched.isCancelled()) {
54→                    processorNodePunctuator.punctuate(sched.node(), timestamp, type, sched.punctuator());
55→                    // sched can be cancelled from within the punctuator
56→                    if (!sched.isCancelled()) {
57→                        pq.add(sched.next(timestamp));
58→                    }
59→                    punctuated = true;
60→                }
61→
62→
63→                top = pq.peek();
64→            }
65→
66→            return punctuated;
67→        }
68→    }
69→
70→    /**
71→     * Returns true if there is a schedule ready to be punctuated.
72→     */
73→    boolean canPunctuate(final long timestamp) {
74→        synchronized (pq) {
75→            PunctuationSchedule top = pq.peek();
76→            while (top != null && top.timestamp <= timestamp) {
77→                if (!top.isCancelled()) {
78→                    return true;
79→                }
80→                // Side-effect: removes cancelled schedules (not externally visible)
81→                pq.poll();
82→                top = pq.peek();
83→            }
84→            return false;
85→        }
86→    }
87→
88→}
