 17→package org.apache.kafka.streams.state.internals;
 18→
 19→import org.apache.kafka.common.utils.Bytes;
 20→import org.apache.kafka.common.utils.CircularIterator;
 21→import org.apache.kafka.common.utils.LogContext;
 22→import org.apache.kafka.streams.KeyValue;
 23→import org.apache.kafka.streams.processor.internals.metrics.StreamsMetricsImpl;
 24→
 25→import org.slf4j.Logger;
 26→
 27→import java.util.Collections;
 28→import java.util.HashMap;
 29→import java.util.Iterator;
 30→import java.util.List;
 31→import java.util.Map;
 32→import java.util.NoSuchElementException;
 33→import java.util.concurrent.atomic.AtomicLong;
 34→
 35→/**
 36→ * An in-memory LRU cache store similar to {@link MemoryLRUCache} but byte-based, not
 37→ * record based
 38→ */
 39→public class ThreadCache {
 40→    private final Logger log;
 41→    private volatile long maxCacheSizeBytes;
 42→    private final StreamsMetricsImpl metrics;
 43→    private final Map<String, NamedCache> caches = new HashMap<>();
 44→
 45→    // Invariant: equal to sum of sizeInBytes of caches
 46→    private final AtomicLong sizeInBytes = new AtomicLong();
 47→
 48→    // internal stats
 49→    private long numPuts = 0;
 50→    private long numGets = 0;
 51→    private long numEvicts = 0;
 52→    private long numFlushes = 0;
 53→
 54→    public interface DirtyEntryFlushListener {
 55→        void apply(final List<DirtyEntry> dirty);
 56→    }
 57→
 58→    public ThreadCache(final LogContext logContext, final long maxCacheSizeBytes, final StreamsMetricsImpl metrics) {
 59→        this.maxCacheSizeBytes = maxCacheSizeBytes;
 60→        this.metrics = metrics;
 61→        this.log = logContext.logger(getClass());
 62→    }
 63→
 64→    public long puts() {
 65→        return numPuts;
 66→    }
 67→
 68→    public long gets() {
 69→        return numGets;
 70→    }
 71→
 72→    public long evicts() {
 73→        return numEvicts;
 74→    }
 75→
 76→    public long flushes() {
 77→        return numFlushes;
 78→    }
 79→
 80→    public synchronized void resize(final long newCacheSizeBytes) {
 81→        final boolean shrink = newCacheSizeBytes < maxCacheSizeBytes;
 82→        maxCacheSizeBytes = newCacheSizeBytes;
 83→        if (shrink) {
 84→            log.debug("Cache size was shrunk to {}", newCacheSizeBytes);
 85→            if (caches.values().isEmpty()) {
 86→                return;
 87→            }
 88→            final CircularIterator<NamedCache> circularIterator = new CircularIterator<>(caches.values());
 89→            while (sizeInBytes.get() > maxCacheSizeBytes) {
 90→                final NamedCache cache = circularIterator.next();
 91→                synchronized (cache) {
 92→                    final long oldSize = cache.sizeInBytes();
 93→                    cache.evict();
 94→                    sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
 95→                }
 96→                numEvicts++;
 97→            }
 98→        } else {
 99→            log.debug("Cache size was expanded to {}", newCacheSizeBytes);
100→        }
101→    }
102→
103→    /**
104→     * The thread cache maintains a set of {@link NamedCache}s whose names are a concatenation of the task ID and the
105→     * underlying store name. This method creates those names.
106→     * @param taskIDString Task ID
107→     * @param underlyingStoreName Underlying store name
108→     */
109→    public static String nameSpaceFromTaskIdAndStore(final String taskIDString, final String underlyingStoreName) {
110→        return taskIDString + "-" + underlyingStoreName;
111→    }
112→
113→    /**
114→     * Given a cache name of the form taskid-storename, return the task ID.
115→     */
116→    public static String taskIDfromCacheName(final String cacheName) {
117→        final String[] tokens = cacheName.split("-", 2);
118→        return tokens[0];
119→    }
120→
121→    /**
122→     * Given a cache name of the form taskid-storename, return the store name.
123→     */
124→    public static String underlyingStoreNamefromCacheName(final String cacheName) {
125→        final String[] tokens = cacheName.split("-", 2);
126→        return tokens[1];
127→    }
128→
129→
130→    /**
131→     * Add a listener that is called each time an entry is evicted from the cache or an explicit flush is called
132→     */
133→    public void addDirtyEntryFlushListener(final String namespace, final DirtyEntryFlushListener listener) {
134→        final NamedCache cache = getOrCreateCache(namespace);
135→        cache.setListener(listener);
136→    }
137→
138→    public void flush(final String namespace) {
139→        numFlushes++;
140→
141→        final NamedCache cache = getCache(namespace);
142→        if (cache == null) {
143→            return;
144→        }
145→
146→        synchronized (cache) {
147→            final long oldSize = cache.sizeInBytes();
148→            cache.flush();
149→            sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
150→        }
151→
152→        if (log.isTraceEnabled()) {
153→            log.trace("Cache stats on flush: #puts={}, #gets={}, #evicts={}, #flushes={}", puts(), gets(), evicts(), flushes());
154→        }
155→    }
156→
157→    public LRUCacheEntry get(final String namespace, final Bytes key) {
158→        numGets++;
159→
160→        if (key == null) {
161→            return null;
162→        }
163→
164→        final NamedCache cache = getCache(namespace);
165→        if (cache == null) {
166→            return null;
167→        }
168→        return cache.get(key);
169→    }
170→
171→    public void put(final String namespace, final Bytes key, final LRUCacheEntry value) {
172→        numPuts++;
173→
174→        final NamedCache cache = getOrCreateCache(namespace);
175→
176→        synchronized (cache) {
177→            final long oldSize = cache.sizeInBytes();
178→            cache.put(key, value);
179→            sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
180→            maybeEvict(namespace, cache);
181→        }
182→    }
183→
184→    public LRUCacheEntry putIfAbsent(final String namespace, final Bytes key, final LRUCacheEntry value) {
185→        final NamedCache cache = getOrCreateCache(namespace);
186→        final LRUCacheEntry result;
187→        synchronized (cache) {
188→            final long oldSize = cache.sizeInBytes();
189→            result = cache.putIfAbsent(key, value);
190→            sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
191→            maybeEvict(namespace, cache);
192→        }
193→
194→        if (result == null) {
195→            numPuts++;
196→        }
197→        return result;
198→    }
199→
200→    public void putAll(final String namespace, final List<KeyValue<Bytes, LRUCacheEntry>> entries) {
201→        for (final KeyValue<Bytes, LRUCacheEntry> entry : entries) {
202→            put(namespace, entry.key, entry.value);
203→        }
204→    }
205→
206→    public LRUCacheEntry delete(final String namespace, final Bytes key) {
207→        final NamedCache cache = getCache(namespace);
208→        if (cache == null) {
209→            return null;
210→        }
211→
212→        final LRUCacheEntry entry;
213→        synchronized (cache) {
214→            final long oldSize = cache.sizeInBytes();
215→            entry = cache.delete(key);
216→            sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
217→        }
218→        return entry;
219→    }
220→
221→    public MemoryLRUCacheBytesIterator range(final String namespace, final Bytes from, final Bytes to) {
222→        return range(namespace, from, to, true);
223→    }
224→
225→    public MemoryLRUCacheBytesIterator range(final String namespace, final Bytes from, final Bytes to, final boolean toInclusive) {
226→        final NamedCache cache = getCache(namespace);
227→        if (cache == null) {
228→            return new MemoryLRUCacheBytesIterator(Collections.emptyIterator(), new NamedCache(namespace, this.metrics));
229→        }
230→        return new MemoryLRUCacheBytesIterator(cache.keyRange(from, to, toInclusive), cache);
231→    }
232→
233→    public MemoryLRUCacheBytesIterator reverseRange(final String namespace, final Bytes from, final Bytes to) {
234→        final NamedCache cache = getCache(namespace);
235→        if (cache == null) {
236→            return new MemoryLRUCacheBytesIterator(Collections.emptyIterator(), new NamedCache(namespace, this.metrics));
237→        }
238→        return new MemoryLRUCacheBytesIterator(cache.reverseKeyRange(from, to), cache);
239→    }
240→
241→    public MemoryLRUCacheBytesIterator all(final String namespace) {
242→        final NamedCache cache = getCache(namespace);
243→        if (cache == null) {
244→            return new MemoryLRUCacheBytesIterator(Collections.emptyIterator(), new NamedCache(namespace, this.metrics));
245→        }
246→        return new MemoryLRUCacheBytesIterator(cache.allKeys(), cache);
247→    }
248→
249→    public MemoryLRUCacheBytesIterator reverseAll(final String namespace) {
250→        final NamedCache cache = getCache(namespace);
251→        if (cache == null) {
252→            return new MemoryLRUCacheBytesIterator(Collections.emptyIterator(), new NamedCache(namespace, this.metrics));
253→        }
254→        return new MemoryLRUCacheBytesIterator(cache.reverseAllKeys(), cache);
255→    }
256→
257→    public long size() {
258→        long size = 0;
259→        for (final NamedCache cache : caches.values()) {
260→            size += cache.size();
261→            if (isOverflowing(size)) {
262→                return Long.MAX_VALUE;
263→            }
264→        }
265→        return size;
266→    }
267→
268→    private boolean isOverflowing(final long size) {
269→        return size < 0;
270→    }
271→
272→    long sizeBytes() {
273→        return sizeInBytes.get();
274→    }
275→
276→    synchronized void close(final String namespace) {
277→        final NamedCache removed = caches.remove(namespace);
278→        if (removed != null) {
279→            sizeInBytes.getAndAdd(-removed.sizeInBytes());
280→            removed.close();
281→        }
282→    }
283→
284→    synchronized void clear(final String namespace) {
285→        final NamedCache cleared = caches.get(namespace);
286→        if (cleared != null) {
287→            sizeInBytes.getAndAdd(-cleared.sizeInBytes());
288→            cleared.clear();
289→        }
290→    }
291→
292→    private void maybeEvict(final String namespace, final NamedCache cache) {
293→        int numEvicted = 0;
294→        while (sizeInBytes.get() > maxCacheSizeBytes) {
295→            // we abort here as the put on this cache may have triggered
296→            // a put on another cache. So even though the sizeInBytes() is
297→            // still > maxCacheSizeBytes there is nothing to evict from this
298→            // namespaced cache.
299→            if (cache.isEmpty()) {
300→                return;
301→            }
302→            final long oldSize = cache.sizeInBytes();
303→            cache.evict();
304→            sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
305→            numEvicts++;
306→            numEvicted++;
307→        }
308→        if (log.isTraceEnabled()) {
309→            log.trace("Evicted {} entries from cache {}", numEvicted, namespace);
310→        }
311→    }
312→
313→    private synchronized NamedCache getCache(final String namespace) {
314→        return caches.get(namespace);
315→    }
316→
317→    private synchronized NamedCache getOrCreateCache(final String name) {
318→        NamedCache cache = caches.get(name);
319→        if (cache == null) {
320→            cache = new NamedCache(name, this.metrics);
321→            caches.put(name, cache);
322→        }
323→        return cache;
324→    }
325→
326→    static class MemoryLRUCacheBytesIterator implements PeekingKeyValueIterator<Bytes, LRUCacheEntry> {
327→        private final Iterator<Bytes> keys;
328→        private final NamedCache cache;
329→        private KeyValue<Bytes, LRUCacheEntry> nextEntry;
330→
331→        MemoryLRUCacheBytesIterator(final Iterator<Bytes> keys, final NamedCache cache) {
332→            this.keys = keys;
333→            this.cache = cache;
334→        }
335→
336→        public Bytes peekNextKey() {
337→            if (!hasNext()) {
338→                throw new NoSuchElementException();
339→            }
340→            return nextEntry.key;
341→        }
342→
343→
344→        public KeyValue<Bytes, LRUCacheEntry> peekNext() {
345→            if (!hasNext()) {
346→                throw new NoSuchElementException();
347→            }
348→            return nextEntry;
349→        }
350→
351→        @Override
352→        public boolean hasNext() {
353→            if (nextEntry != null) {
354→                return true;
355→            }
356→
357→            while (keys.hasNext() && nextEntry == null) {
358→                internalNext();
359→            }
360→
361→            return nextEntry != null;
362→        }
363→
364→        @Override
365→        public KeyValue<Bytes, LRUCacheEntry> next() {
366→            if (!hasNext()) {
367→                throw new NoSuchElementException();
368→            }
369→            final KeyValue<Bytes, LRUCacheEntry> result = nextEntry;
370→            nextEntry = null;
371→            return result;
372→        }
373→
374→        private void internalNext() {
375→            final Bytes cacheKey = keys.next();
376→            final LRUCacheEntry entry = cache.get(cacheKey);
377→            if (entry == null) {
378→                return;
379→            }
380→
381→            nextEntry = new KeyValue<>(cacheKey, entry);
382→        }
383→
384→        @Override
385→        public void close() {
386→            // do nothing
387→        }
388→    }
389→
390→    static class DirtyEntry {
391→        private final Bytes key;
392→        private final byte[] newValue;
393→        private final LRUCacheEntry recordContext;
394→
395→        DirtyEntry(final Bytes key, final byte[] newValue, final LRUCacheEntry recordContext) {
396→            this.key = key;
397→            this.newValue = newValue;
398→            this.recordContext = recordContext;
399→        }
