621→                            + " task " + failedTask.id() + " was removed from the failed tasks.");
622→                        future.complete(new RemovedTaskResult(failedTask, exceptionAndTask.exception()));
623→                        return true;
624→                    }
625→                }
626→                return false;
627→            } finally {
